INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('ΜΠΙΛΙΑΡΔΟ RASSON WOLF 9FT SILVER FLUOROCARBON ΜΠΙΛΙΑΡΔΟ RASSON WOLF 9FT SILVER FLUOROCARBON', 'μπιλιαρδο-rasson-wolf-9ft-silver-fluorocarbon-μπιλιαρδο-rasson-wolf-9ft-silver-fluorocarbon', 'Μοντέλο:BIL.AM9.04145 Διαστάσεις:285.00cm x 155.00cm x 0.00cm RASSON WOLF 9FT SILVER FLUOROCARBON Μια ακόμα νέα πρόταση της Rasson, το μοντέλο Wolf, ήρθε για να μείνει! Σε μέγεθος 9 ποδών, με εξωτερικές διαστάσεις 292×164cm, αγωνιστικό χώρο 254×127cm, και βάρος περί τα 550 κιλά, είναι μια απο τις τελευταίες εκπλήξεις του πασίγνωστου εργοστασίου... Η ανθεκτική του κατασκευή και η εξαιρετικής ακρίβειας λείανση του πετρώματος γραφίτη "Rasson K-Patern 30mm" που διαθέτει, εκπλήσσει ευχάριστα και τον ', 6499, 'EUR', 'Tables', 'Rasson', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/WOLFSILVERNEW-550x550w.jpg?v=1754561380","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Wolf_WhiteFluorocarbon_8_-550x550w.jpg?v=1754561379","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Wolf_WhiteFluorocarbon_-1-550x550w.jpg?v=1754561380","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Wolf_WhiteFluorocarbon_2_-550x550w.jpg?v=1754561380","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Wolf_WhiteFluorocarbon_1_-550x550w.jpg?v=1754561380"]', 1, 0, datetime('now'));
INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('ΜΠΙΛΙΑΡΔΟ 9FT RASSON ACURRA GREY ΜΕ ΣΥΣΤΗΜΑ ΕΠΙΣΤΡΟΦΗΣ ΜΠΙΛΙΩΝ', 'μπιλιαρδο-9ft-rasson-acurra-grey-με-συστημα-επιστροφησ-μπιλιων', 'Μοντέλο:BIL.AM9.66466 Διαστάσεις:285.00cm x 155.00cm x 0.00cm RASSON ACCURA 9ft GREY ΜΕ ΣΥΣΤΗΜΑ ΕΠΙΣΤΡΟΦΗΣ ΜΠΙΛΙΩΝ Πέρασαν 30 χρόνια από τότε που ένα μοντέλο Αμερικάνικου μπιλιάρδου μπήκε τόσο εντυπωσιακά στην Ευρωπαϊκή αγορά... Είναι η πρώτη φορά πού σε ένα τραπέζι μπιλιάρδου έχει συνδυαστεί τόσο αρμονικά το αέρινο design, με το χαμηλό κόστος και την άριστη παικτικότητα ενός έργου τέχνης που τον τελευταίο καιρο δοκιμάζεται διαρκώς στα μεγαλύτερα πρωταθλήματα του κόσμου. Το αγωνιστικό αυτό μοντέ', 5199, 'EUR', 'Tables', 'Rasson', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/ACCGRBR_1-550x550w.jpg?v=1754561170","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/ACCGRBR_3-550x550w.jpg?v=1754561170","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/ACCGRBR_2-550x550w.jpg?v=1754561170"]', 1, 0, datetime('now'));
