INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('Πετσι στεκας How Hard', 'πετσι-στεκας-how-hard', 'Κωδικος:QC.1006.0053 Το HOW είναι αφιερωμένο στο σχεδιασμό και την παραγωγή των πιο επαγγελματικών πετσιών που σας δίνουν τον μέγιστο έλεγχο και την ανάδραση μεταξύ της μπαλας και της στέκας διατηρώντας παράλληλα τη στιβαρή ισχύ. Για την παραγωγή του επαγγελματικού πετσιού, του πιο σημαντικό στοιχείο είναι η επιλογή του δέρματος που είναι από χοίρο, το HOW χρησιμοποιεί μόνο το 5% ολόκληρου του κομματιού πρώτης τάξεως ιαπωνικού γουρουνίσιουδερμας που είναι καλύτερο για άκρες πισίνας. Επειδή έχει ', 20, 'EUR', 'Accessories', 'How Hard', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/how-tips-general-550x550.jpg?v=1754315142"]', 1, 0, datetime('now'));
