INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('Predactor Victory Hard', 'predactor-victory-hard', 'Κωδικος:QC.1006.007 Το νέο Predator Victory πετσάκι στέκας υψηλής απόδοσης είναι μια άκρη αποτελούμενη από 8-στρώματα υψηλής ποιότητας πετσάκι που έχει σχεδιαστεί για να διατηρήσει τη βέλτιστη συμπίεση για ολόκληρη τη ζωή του στην άκρη και να διατηρεί το σχήμα του . Υψηλή χρωματική αντίθεση του επιτρέπει την καλύτερη παρατήρηση και τη διαμόρφωση σε συνθήκες χαμηλού φωτισμού. Έχει δοκιμαστεί από κορυφαίους επαγγελματίες παίκτες και είναι διαθέσιμο σε χαμηλής, μέσης και σκληρό.', 25, 'EUR', 'Accessories', '9BallShop', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/predator_tip-550x550_3be6d1c1-68b4-4dea-899c-870e2aff8d72.jpg?v=1754314750"]', 1, 0, datetime('now'));
