INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('Τραπεζι Αμερικανικου Μπιλιαρδου Terminator,9 ft, Μαυρη Λακα', 'τραπεζι-αμερικανικου-μπιλιαρδου-terminator-9-ft-μαυρη-λακα', 'Κωδικος:BT.1001.010 Το μπιλιάρδο Terminator, 9 ft είναι ένα τραπέζι τύπου "ELIMINATOR" όπως συνηθίζεται να ονομάζονται τα τραπέζια αυτής της κατηγορίας που όμως δεν έχει καμιά σχέση η ποιότητα κατασκευής του με αυτά που κατασκευάζονται στην Κίνα από όλους τους διεθνείς οίκους χωρίς να ξεφεύγει το κόστος πώλησης του σε σχέση με των ανταγωνιστών του . Παρακάτω θα αναλύσουμε τα τεχνικά χαρακτηριστικά του. Τέσσερις Ρεγουλατόροι στα πόδια για απόλυτη ευθυγράμμιση όποια και αν είναι η κλίση του πατώμα', 3540, 'EUR', 'Tables', '9BallShop', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Terminator_laka1-550x550w.jpg?v=1753967215"]', 1, 0, datetime('now'));
INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('Τραπεζι Αμεριανικου μπιλιαρδου Hurricane, 9 ft., Matt-Black', 'τραπεζι-αμεριανικου-μπιλιαρδου-hurricane-9-ft-matt-black', 'Κωδικος:BT.1121.017 Τραπέζι Αμεριάνικου μπιλιάρδου Hurricane, 9 ft., Matt-Black Τραπέζι μπιλιάρδου Premium Τουρνουά με μοντέρνα εμφάνιση Το τραπέζι μπιλιάρδου Hurricane ταιριάζει τέλεια σε ιδιωτικές αίθουσες μπιλιάρδου καθώς και σε αίθουσες παιχνιδιών. Ο μοντέρνος σχεδιασμός του σε συνδυασμό με τα καλά συναρμολογημένα υλικά υψηλής ποιότητας είναι εντυπωσιακός. Έρχεται με ένα φυσικό σχιστόλιθο 3 τεμαχίων, 25 mm, το οποίο μπορεί να ευθυγραμιστεί με 26 ρυθμιζόμενους ρεγουλατόρους και επομένως μπορε', 4340, 'EUR', 'Tables', '9BallShop', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Hurricane_black_1-550x550w.jpg?v=1753967061"]', 1, 0, datetime('now'));
