INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('Προέκταση Στέκας Universal 27cm Με Βίδα Αλουμινίου', 'προέκταση-στέκας-universal-27cm-με-βίδα-αλουμινίου-1', 'Μοντέλο:ACC.EXT.0101 Διαστάσεις:27.00cm x 0.00cm x 0.00cm Προέκταση στέκας Universal 27cm με βίδα αλουμινίου. Το συγκεκριμένο μοντέλο είναι προσαρμόσιμο στα περισσότερα μοντέλα της Universal Γαλλικού και Αμερικάνικου μπιλιάρδου, και επίσης είναι συμβατή με σχεδόν όλα τα μοντέλα στεκών Adam και Buffalo Γαλλικού και Αμερικάνικου της τελευταίας επταετίας. Για πιθανή τοποθέτησή της σε άλλα μοντέλα στεκών, παρακαλώ ζητήστε μας πληροφορίες.', 89.99, 'EUR', 'Accessories', 'Universal', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Image_1749-550x550w.jpg?v=1753889927","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Image_1751-550x550w_1.jpg?v=1753889900"]', 1, 0, datetime('now'));
