INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('ΠΡΟΕΚΤΑΣΗ ΣΤΕΚΑΣ BUFFALO CARBON SET 3 IN 1 (3 ΤΕΜ)', 'προεκταση-στεκασ-buffalo-carbon-set-3-in-1-3-τεμ', 'Μοντέλο:ACC.EXT.01001 Προεκταση Στεκας Buffalo Carbon Extension Set 3 in 1 (3 τεμ.) Σετ Carbon Extension τριών τεμαχίων, απο την διασημη Buffalo. Κατάλληλο για όλες τις στεκες με συγχρονο σύστημα βάρους Συνολικό μήκος 22,5 cm Μήκος του τμήματος 1: 5 cm Μήκος του τμηματος 2: 7,5 cm Μήκος του τμηματος 3: 10 cm Υλικό: Carbon', 119.99, 'EUR', 'Accessories', 'Buffalo', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/carbonextension-550x550w.jpg?v=1753889311","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/5890.540_3_1-550x550w.jpg?v=1753889322","https://cdn.shopify.com/s/files/1/0921/7022/3996/files/5890.540_2_1-550x550w.jpg?v=1753889331"]', 1, 0, datetime('now'));
INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('Προέκταση Στέκας Adam 27cm - Λεπτό Μεταλλικό Βίδωμα', 'προέκταση-στέκας-adam-27cm-λεπτό-μεταλλικό-βίδωμα', 'Μοντέλο:ACC.EXT.0103 Διαστάσεις:27.00cm x 0.00cm x 0.00cm Προέκταση στέκας Adam 27cm με λεπτό μεταλλικό βίδωμα. Η προέκταση αυτή είναι προσαρμόσιμη στο πίσω μέρος του κοντακιού παλιών μοντέλων στεκών Adam, Buffalo, κλπ., καθώς επίσης και σε πάρα πολλές άλλες στέκες. Προσοχή: Στις περισσότερες περιπτώσεις θα πρέπει να δημιουργήσετε μία μικρή και εύκολη υποδομή στο πίσω μέρος του κοντακιού σας. Ζητήστε μας περισσότερες πληροφορίες, αφού μας στείλετε φωτογραφίες της στέκας σας.', 74.99, 'EUR', 'Accessories', 'Adam', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/Image_7170-550x550w.jpg?v=1753889140"]', 1, 0, datetime('now'));
INSERT INTO Product (name, slug, description, price, currency, category, brand, images, inStock, featured, createdAt) VALUES ('Προέκταση Μεσαίας Ένωσης Adam 20cm Για Στέκες Double Joint', 'προέκταση-μεσαίας-ένωσης-adam-20cm-για-στέκες-double-joint', 'Στοκ:Σε Διαθεσιμότητα Μοντέλο:ACC.EXT.0104 Διαστάσεις:20.00cm x 0.00cm x 0.00cm Προέκταση Μεσαίας Ένωσης Adam 20cm. Η συγκεκριμένη προέκταση είναι κατάλληλη για κάθε στέκα της Adam με βίδωμα Double Joint, αλλά και για κάθε στέκα άλλης εταιρείας που χρησιμοποιεί τον ίδιο τύπο βιδώματος. Τοποθετείται ενδιάμεσα, μεταξύ κοντακιού και φλές.', 89.99, 'EUR', 'Accessories', 'Adam', '["https://cdn.shopify.com/s/files/1/0921/7022/3996/files/5935020-p-550x550w.jpg?v=1753888954"]', 1, 0, datetime('now'));
